        lags = [21, 63, 126, 252]
        weights = [12, 4, 2, 1]
        score = 0.0
        for lag, w in zip(lags, weights):
            idx = i - lag
            if idx < 0 or px[idx] <= 0:
                return -999.0
            score += w * (p0 / px[idx] - 1.0)
        return score

