        defensive  = [s for s in ['AGG', 'TLT', 'GLD'] if s in closes]

        p = self.params
        warmup = 252 + 10
        last_rebal = -p['rebalance_period']
        current_alloc = {s: 0.0 for s in syms}

        for i in range(warmup, n):
