                    if valid_def:
                        best_def = max(valid_def, key=lambda x: x[1])[0]
                        current_alloc[best_def] = current_alloc.get(best_def, 0.0) + safe_alloc

                # Hard cap total at base_size
                total = sum(current_alloc.values())
